public:
    bool detectCapitalUse(string word) {
        // Check all uppercase
        bool allUpper = true;
        for (char c : word) {
            if (!isupper(c)) {
                allUpper = false;
                break;
            }
        }
        if (allUpper) return true;

        // Check all lowercase
        bool allLower = true;
        for (char c : word) {
            if (!islower(c)) {
                allLower = false;
                break;
            }
        }
        if (allLower) return true;

        // Check first uppercase and rest lowercase
        if (!word.empty() && isupper(word[0])) {
            for (size_t i = 1; i < word.size(); ++i) {
                if (!islower(word[i])) {
                    return false;
                }
            }
            return true;
        }

        return false;
    }
};

